mapper.select:
SELECT p.*, (SELECT COUNT(DISTINCT pr.user_id) FROM project_roles pr WHERE pr.project_id = p.id) AS contributor_count, (SELECT COUNT(*) FROM project_comments pc WHERE pc.project_id = p.id) AS comment_count, (SELECT COUNT(*) FROM project_pages pp WHERE pp.project_id = p.id) AS total_pages, (SELECT COUNT(*) FROM project_pages pp WHERE pp.project_id = p.id AND p.status = 'COMPLETED') AS pages_completed, COALESCE(p.quality_score, 0) AS quality_score FROM projects p
AND p.status = #{status}
AND p.difficulty = #{difficulty}
AND LOWER(p.title) LIKE LOWER(CONCAT('%', #{title}, '%'))
AND p.genre = #{genre}
ORDER BY ${sortColumn} ${sortType} LIMIT #{limit} OFFSET #{offset}

mapper.update:
UPDATE projects
title = #{title}, description = #{description}, author = #{author}, original_source = #{originalSource}, difficulty = CAST(#{difficulty} AS difficulty_level), status = CAST(#{status} AS project_status), priority = CAST(#{priority} AS project_priority), original_language = #{originalLanguage}, original_title = #{originalTitle}, is_public_domain = #{isPublicDomain}, copyright_status = #{copyrightStatus}, estimated_pages = #{estimatedPages}, estimated_word_count = #{estimatedWordCount}, total_pages = #{totalPages}, transcription_completed_pages = #{transcriptionCompletedPages}, translation_completed_pages = #{translationCompletedPages}, editing_completed_pages = #{editingCompletedPages}, illustration_completed_pages = #{illustrationCompletedPages}, formatted_pages = #{formattedPages}, pages_completed = #{pagesCompleted}, overall_progress = #{overallProgress}, issues_reported = #{issuesReported}, issues_resolved = #{issuesResolved}, is_published = #{isPublished}, start_date = #{startDate}, expected_completion_date = #{expectedCompletionDate}, actual_completion_date = #{actualCompletionDate}, cover_image_url = #{coverImageUrl}, book_slug = #{bookSlug}, original_publication_year = #{originalPublicationYear}, quality_score = #{qualityScore}, updated_at = #{updatedAt}
WHERE id = #{id}

UPDATE projects
SET updated_at = #{now}
WHERE id = #{projectId}

UPDATE projects
SET view_count = COALESCE(view_count, 0) + 1
WHERE id = #{id}

